import Vue from 'vue'
import VueRouter from 'vue-router'
import HomeView from '../views/HomeView.vue'
import Error404 from '../views/other/error404.vue'

Vue.use(VueRouter)

//设置type表示页面是菜单类型还是页面，还是跳转的页面
const routes = [
  {
    path: '/',
    name: 'home',
    component: HomeView,
    meta: { title: '首页', icon: '' },
    type: 'menu',
  },
  {
    path: '/blogArtices',
    name: 'blog',
    meta: { title: '编程技术', icon: 'fa-home' },
    component: (resolve) => require(['../views/function/BlogPage.vue'],resolve),
    type: 'menu',
  },
  {
    path: '/techArtices',
    name: 'tech',
    meta: { title: '科技前沿', icon: 'fa-home' },
    //component: () => import(/* webpackChunkName: "about" */''),
    type: 'menu',
  },
  {
    path: '/resourceList',
    name: 'resource',
    meta: { title: '福利资源', icon: 'fa-home' },
    //component: () => import(/* webpackChunkName: "about" */''),
    type: 'menu',
  },
  {
    path: '/leaveMessage',
    name: 'message',
    meta: { title: '留言给我', icon: 'fa-home' },
    //component: () => import(/* webpackChunkName: "about" */''),
    type: 'menu',
  },
  {
    path: '/lifeArticles',
    name: 'myLife',
    meta: { title: '生活随笔', icon: 'fa-home' },
    //component: () => import(/* webpackChunkName: "about" */''),
    type: 'menu',
  },
  {
    path: '/honeyComb',
    name: 'honeyComb',
    meta: { title: '蜂窝结构', icon: 'fa-home' },
    component: (resolve) => require(['../components/HoneyComb.vue'],resolve),
    type: 'page',
  },
  {
    path: '/about',
    name: 'about',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: (resolve) => require(['../views/about/AboutUS.vue'],resolve),
    //component: () => import(/* webpackChunkName: "about" */ '../views/about/AboutUS.vue'),
    meta: { title: '关于', icon: '' },
    type: 'menu',
  },
  {
    path: '/404',
    name: 'error',
    component: Error404,
    meta: { title: '404', icon: '' },
    type: 'other',
    hidden: true
  },
  //这个*匹配必须放在最后，将改路由配置放到所有路由的配置信息的最后，否则会其他路由path匹配造成影响。     
  {
    path: '*',
    redirect: '/404',
    type: 'other',
    hidden: true
  }
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})
//beforeEach每次进行路由跳转时都会执行
router.beforeEach((to, from, next) => {
  if (to.matched.length === 0) {
    from.path ? next({ name: from.name }) : next('/404')
  } else {
    next()
  }
})
export default router
